-- Migration 113: import NPC data from the player Google Sheet.
--
-- Source: docs.google.com/spreadsheets/d/1O8KM25y1wdyorNHYc2mXvnl0A84JX2gxFlN0jRVk-jY
-- (sheet "NPC", 185 rows: 150 visible + 35 hidden).
--
-- The sheet is the canonical source of NPC data; the DB had only the 10
-- stub NPCs seeded in 001 + nothing else. This migration brings everything
-- in, lossless.
--
-- Strategy (single transaction; temp table):
--   1. Pre-step: rename the one DB entry whose title in the sheet has
--      changed:  «Хаслуш Экзетери»  →  «Хаслуш Икзетери»  (the sheet's
--      «Старый Арт» column itself records the old spelling — preserved
--      in fields.art_name + fields.alt_name). Guarded by NOT EXISTS so
--      re-running is safe.
--
--   2. Load all 185 (csv_title, patch_jsonb) into a temp table.
--
--   3. UPDATE — for each row whose csv_title matches an existing
--      campaign-scoped NPC node, merge the patch into `fields` via
--      `fields = fields || patch`. This hits the 10 seeded NPCs (Тайвен,
--      Ильза Зилети, Кайрон, Зориан Казински, Хаслуш Икзетери (renamed),
--      Имайя Курошка, Бенисек, Акоджа Строуз, Лайонел Вирион, Нора Буул)
--      and any NPC manually created via the catalog UI with a matching
--      title. `fields.tags` is NOT touched (preserves seed-assigned tags).
--
--   4. INSERT — for everyone whose title doesn't exist yet, create the
--      node with the patch as the initial `fields` value plus `tags: []`
--      (no auto-tag derivation — group/region/source/status already
--      live as separate scalar fields, more reliable than tag arrays).
--
-- Field keys (all under `nodes.fields`, omitted when the sheet cell was
-- blank or "-"; descriptions of CSV columns in parentheses):
--   description       — Краткое описание
--   status            — Статус             (already in node_type defaults)
--   name_en           — Английское имя
--   art_name          — Старый Арт          (art-file reference under old name)
--   ai_art_name       — AI Арт              (AI-art-file reference)
--   source            — Источник            ("Канон" / "Мастер" / "Предыстория игрока")
--   region            — Регион
--   group             — Группа
--   age               — Возраст             (string; "около 30", "70+", etc.)
--   height_cm         — Рост                (integer when numeric)
--   skills            — Навыки/особенности
--   dm_notes          — Игровые заметки     (DM-side notes)
--   appearances       — Появления           (multi-line: "Игра N\n- M петля, K странствий")
--   old_notes         — Старые заметки      (ONLY if differs from description; 39/185)
--   hidden            — Hide column         (true on 35 rows; soft flag — UI does not
--                                            filter on it yet, see caveat below)
--   alt_name          — old DB title        (only for the renamed Хаслуш entry)
--
-- IMPORTANT visibility caveat:
--   35 NPCs are marked `Hide=TRUE` in the sheet — spoilers, DM-only,
--   not-yet-revealed family members, etc. They land in the DB with
--   `fields.hidden: true` BUT there is currently NO node-level visibility
--   filtering in the UI (spec-022 will introduce private/party_draft/
--   published states). Until then, hidden NPCs are visible to players
--   in the catalog the same way as any other node. The `hidden` flag
--   here is a forward-compatibility marker — spec-022 can flip them
--   to `visibility = 'private'` in a follow-up migration. If exposing
--   these 35 to players right now is unacceptable, DELETE them after
--   applying:
--     delete from nodes
--      where campaign_id = '00000000-0000-0000-0000-000000000001'
--        and type_id    = '10000000-0000-0000-0000-000000000002'
--        and fields->>'hidden' = 'true';
--
-- Idempotent: rename is NOT-EXISTS guarded; UPDATEs are deterministic
-- jsonb merges; INSERTs are NOT-EXISTS guarded by (campaign, type, title).

BEGIN;

-- ────────────── 1. Rename Хаслуш Экзетери → Хаслуш Икзетери ──────────────

update nodes
   set title = 'Хаслуш Икзетери',
       updated_at = now()
 where campaign_id = '00000000-0000-0000-0000-000000000001'
   and type_id    = '10000000-0000-0000-0000-000000000002'
   and title      = 'Хаслуш Экзетери'
   and not exists (
     select 1 from nodes n2
      where n2.campaign_id = '00000000-0000-0000-0000-000000000001'
        and n2.type_id    = '10000000-0000-0000-0000-000000000002'
        and n2.title      = 'Хаслуш Икзетери'
   );

-- ────────────── 2. Load all 185 sheet rows into a temp table ──────────────

create temp table _npc_import (
  title text primary key,
  patch jsonb not null
) on commit drop;


-- ────────────── 3. UPDATE existing NPC nodes (merge patches) ──────────────

update nodes n
   set fields     = n.fields || ni.patch,
       updated_at = now()
  from _npc_import ni
 where n.campaign_id = '00000000-0000-0000-0000-000000000001'
   and n.type_id    = '10000000-0000-0000-0000-000000000002'
   and n.title      = ni.title;

-- ────────────── 4. INSERT new NPC nodes ──────────────
-- Note: `tags` initialized to []; status/region/group live as scalars
-- in `fields` (more queryable + less duplicate-prone than tags).

select
  '00000000-0000-0000-0000-000000000001',
  '10000000-0000-0000-0000-000000000002',
  ni.title,
  ni.patch || jsonb_build_object('tags', '[]'::jsonb)
  from _npc_import ni
 where not exists (
   select 1 from nodes n
    where n.campaign_id = '00000000-0000-0000-0000-000000000001'
      and n.type_id    = '10000000-0000-0000-0000-000000000002'
      and n.title      = ni.title
 );

COMMIT;
